     1→// SPDX-License-Identifier: BUSL-1.1
     2→pragma solidity 0.8.26;
     3→
     4→import {IVerifierProxy} from "@chainlink/contracts/src/v0.8/llo-feeds/v0.5.0/interfaces/IVerifierProxy.sol";
     5→import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";
     6→import {IPriceManager} from "src/interfaces/IPriceManager.sol";
     7→
     8→import {EmergencyWithdrawer} from "src/EmergencyWithdrawer.sol";
     9→import {LinkReceiver} from "src/LinkReceiver.sol";
    10→import {PausableWithAccessControl} from "src/PausableWithAccessControl.sol";
    11→import {Errors} from "src/libraries/Errors.sol";
    12→import {Roles} from "src/libraries/Roles.sol";
    13→
    14→import {IERC165} from "@openzeppelin/contracts/utils/introspection/IERC165.sol";
    15→import {SafeCast} from "@openzeppelin/contracts/utils/math/SafeCast.sol";
    16→import {EnumerableSet} from "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
    17→
    18→/// @title PriceManager Contract.
    19→/// @notice This contract implements functionality to verify and store Data Streams reports from
    20→/// the Data Streams API. It also provides a fallback mechanism to use Chainlink data feeds in case
    21→/// the Data Streams prices are stale.
    22→abstract contract PriceManager is LinkReceiver, EmergencyWithdrawer, IPriceManager {
    23→  using EnumerableSet for EnumerableSet.AddressSet;
    24→  using SafeCast for int256;
    25→  using SafeCast for uint256;
    26→
    27→  /// @notice This event is emitted when an asset is added to the allow list
    28→  /// @param asset The address of the asset that was added to the allow list
    29→  event AssetAddedToAllowlist(address asset);
    30→  /// @notice This event is emitted when an asset is removed from the allowlist
    31→  /// @param asset The address of the asset that was removed from the allowlist
    32→  event AssetRemovedFromAllowlist(address asset);
    33→  /// @notice This event is emitted when the VerifierProxy address is set.
    34→  /// @param verifierProxy The address of the new VerifierProxy contract.
    35→  event VerifierProxySet(address verifierProxy);
    36→  /// @notice This event is emitted when a new asset price is transmitted.
    37→  /// @param asset The address of the asset.
    38→  /// @param price The new price of the asset, scaled to 18 decimals.
    39→  event PriceTransmitted(address indexed asset, uint256 price);
    40→  /// @notice This event is emitted when Data Streams feed information is updated.
    41→  /// @param asset The address of the asset.
    42→  /// @param feedInfo The data streams and data feeds infos for the asset.
    43→  event FeedInfoUpdated(address indexed asset, FeedInfo feedInfo);
    44→
    45→  /// @notice This error is thrown when an unsupported report version is encountered.
    46→  /// @param reportVersion The unsupported report version.
    47→  error InvalidFeedVersion(bytes32 dataStreamsFeedId, uint16 reportVersion);
    48→  /// @notice This error is thrown when trying to set an invalid feed decimals e.g. zero for a Streams data or a
    49→  /// different value that the on-chain data feed.
    50→  /// @param dataStreamsFeedId The dataStreamsFeedId with invalid decimals.
    51→  error InvalidFeedDecimals(bytes32 dataStreamsFeedId);
    52→  /// @notice This error is thrown when trying to transmit a report for a feed that is not allowlisted.
    53→  /// @param dataStreamsFeedId The non-allowlisted dataStreamsFeedId.
    54→  error FeedNotAllowlisted(bytes32 dataStreamsFeedId);
    55→
    56→  /// @notice Data Streams report schema v3 (crypto streams).
    57→  struct ReportV3 {
    58→    bytes32 dataStreamsFeedId; //                 Unique identifier for the data stream.
    59→    uint32 validFromTimestamp; // ───╮ Start timestamp of price validity period (seconds).
    60→    uint32 observationsTimestamp; // │ End timestamp of price validity period (seconds).
    61→    uint192 nativeFee; // ───────────╯ Verification cost in native blockchain tokens.
    62→    uint192 linkFee; // ─────────────╮ Verification cost in LINK tokens.
    63→    uint32 expiresAt; //─────────────╯ Timestamp when this report expires (seconds).
    64→    int192 price; //                   DON consensus median price.
    65→    int192 bid; //                     Simulated buy impact price at X% liquidity depth.
    66→    int192 ask; //                     Simulated sell impact price at X% liquidity depth.
    67→  }
    68→
    69→  /// @notice The parameters for adding or updating feed information.
    70→  struct FeedInfo {
    71→    bytes32 dataStreamsFeedId; //                       Unique identifier for the data stream.
    72→    AggregatorV3Interface usdDataFeed; // ─╮ Address of the data feed usd feed.
    73→    uint32 stalenessThreshold; //          │ Maximum age of the price data (seconds).
    74→    uint8 dataStreamsFeedDecimals; // ─────╯ Number of decimals in the reported price.
    75→  }
    76→
    77→  /// @notice The parameters for adding or updating feed information.
    78→  struct ApplyFeedInfoUpdateParams {
    79→    address asset; // Address of the asset.
    80→    FeedInfo feedInfo; // The asset feeds configurations.
    81→  }
    82→
    83→  /// @notice Stored price information.
    84→  struct DataStreamsPriceInfo {
    85→    uint224 usdPrice; // ─╮ USD price scaled to 18 decimals.
    86→    uint32 timestamp; // ─╯ Timestamp of the price (seconds).
    87→  }
    88→
    89→  /// @notice The Data Streams report schema version supported by this contract.
    90→  uint256 private constant STREAMS_REPORT_V3 = 3;
    91→  /// @notice The number of decimals to which prices are scaled to (18).
    92→  uint256 internal constant PRICE_DECIMALS = 18;
    93→
    94→  /// @notice The Data Streams VerifierProxy contract.
    95→  IVerifierProxy internal immutable i_streamsVerifierProxy;
    96→
    97→  /// @notice Array of all the enabled auction for this contract.
    98→  EnumerableSet.AddressSet internal s_allowlistedAssets;
    99→
   100→  /// @notice Mapping of asset addresses to their USD data feed contracts.
   101→  mapping(address asset => FeedInfo feedInfo) internal s_feedInfo;
   102→  /// @notice Mapping of Data Streams feed IDs to asset.
   103→  mapping(bytes32 dataStreamsFeedId => address asset) internal s_dataStreamsFeedIdToAsset;
   104→  /// @notice Mapping of asset to data streams transmitted price.
   105→  mapping(address asset => DataStreamsPriceInfo streamsPrice) internal s_dataStreamsPrice;
   106→
   107→  constructor(
   108→    uint48 adminRoleTransferDelay,
   109→    address admin,
   110→    address verifierProxy,
   111→    address linkToken,
   112→    ApplyFeedInfoUpdateParams[] memory feedsInfo
   113→  ) LinkReceiver(linkToken) EmergencyWithdrawer(adminRoleTransferDelay, admin) {
   114→    if (verifierProxy == address(0)) {
   115→      revert Errors.InvalidZeroAddress();
   116→    }
   117→
   118→    i_streamsVerifierProxy = IVerifierProxy(verifierProxy);
   119→
   120→    if (feedsInfo.length > 0) {
   121→      _applyFeedInfoUpdates(feedsInfo, new address[](0));
   122→    }
   123→
   124→    emit VerifierProxySet(verifierProxy);
   125→  }
   126→
   127→  // ================================================================================================
   128→  // │                                      Price Transmission                                      │
   129→  // ================================================================================================
   130→
   131→  /// @inheritdoc IPriceManager
   132→  /// @dev - The function does not handle LINK fee payment to the VerifierProxy, it is assumed that fees are waived.
   133→  function transmit(
   134→    bytes[] calldata unverifiedReports
   135→  ) external onlyRole(Roles.PRICE_ADMIN_ROLE) {
   136→    if (unverifiedReports.length == 0) {
   137→      revert Errors.EmptyList();
   138→    }
   139→
   140→    for (uint256 i; i < unverifiedReports.length; ++i) {
   141→      // Decode the unverified report.
   142→      (, bytes memory reportData,,,) =
   143→        abi.decode(unverifiedReports[i], (bytes32[3], bytes, bytes32[], bytes32[], bytes32));
   144→
   145→      bytes32 dataStreamsFeedId = bytes32(reportData);
   146→
   147→      if (s_dataStreamsFeedIdToAsset[dataStreamsFeedId] == address(0)) {
   148→        revert FeedNotAllowlisted(dataStreamsFeedId);
   149→      }
   150→    }
   151→
   152→    // Verify report through the proxy, decode & store prices.
   153→    bytes[] memory verifiedReports = i_streamsVerifierProxy.verifyBulk(unverifiedReports, abi.encode(i_linkToken));
   154→
   155→    for (uint256 i; i < verifiedReports.length; ++i) {
   156→      ReportV3 memory report = abi.decode(verifiedReports[i], (ReportV3));
   157→      address asset = s_dataStreamsFeedIdToAsset[report.dataStreamsFeedId];
   158→      FeedInfo storage feedInfo = s_feedInfo[asset];
   159→
   160→      uint256 usdPrice = int256(report.price).toUint256();
   161→
   162→      if (report.observationsTimestamp < block.timestamp - feedInfo.stalenessThreshold) {
   163→        revert Errors.StaleFeedData();
   164→      }
   165→
   166→      // Scale price to 18 decimals.
   167→      uint8 feedDecimals = feedInfo.dataStreamsFeedDecimals;
   168→      if (feedDecimals < PRICE_DECIMALS) {
   169→        usdPrice = (usdPrice * 10 ** (PRICE_DECIMALS - feedDecimals));
   170→      } else if (feedDecimals > PRICE_DECIMALS) {
   171→        usdPrice = (usdPrice / 10 ** (feedDecimals - PRICE_DECIMALS));
   172→      }
   173→
   174→      if (usdPrice == 0) {
   175→        revert Errors.ZeroFeedData();
   176→      }
   177→
   178→      s_dataStreamsPrice[asset] =
   179→        DataStreamsPriceInfo({usdPrice: usdPrice.toUint224(), timestamp: report.observationsTimestamp});
   180→
   181→      emit PriceTransmitted(asset, usdPrice);
   182→    }
   183→  }
   184→
   185→  // ================================================================================================
   186→  // │                                       Feeds Management                                       │
   187→  // ================================================================================================
   188→
   189→  /// @notice Adds, updates or removes feeds information.
   190→  /// @dev precondition - the caller must have the ASSET_ADMIN_ROLE.
   191→  /// @param adds List of feed information to add or update.
   192→  /// @param removes List of assets to remove.
   193→  function applyFeedInfoUpdates(
   194→    ApplyFeedInfoUpdateParams[] memory adds,
   195→    address[] memory removes
   196→  ) external onlyRole(Roles.ASSET_ADMIN_ROLE) {
   197→    _applyFeedInfoUpdates(adds, removes);
   198→  }
   199→
   200→  /// @notice Internal function to add, update or remove feeds information.
   201→  /// @dev precondition - the adds and removes lists must not both be empty.
   202→  /// @dev precondition - removed asset must be already allowlisted.
   203→  /// @dev precondition - added/updated feed asset address must not be zero.
   204→  /// @dev precondition - added/updated feed data feed address and data streams feed id must not both be zero.
   205→  /// @dev precondition - added/updated feed decimals must be greater than zero.
   206→  /// @dev precondition - added/updated when data streams feed id is set it must be of version 3.
   207→  /// @param adds List of feed information to add or update (allowlists new assets).
   208→  /// @param removes List of assets to remove (removes assets from allowlist and clean up feed info state).
   209→  function _applyFeedInfoUpdates(
   210→    ApplyFeedInfoUpdateParams[] memory adds,
   211→    address[] memory removes
   212→  ) internal {
   213→    if (adds.length == 0 && removes.length == 0) {
   214→      revert Errors.EmptyList();
   215→    }
   216→
   217→    for (uint256 i; i < removes.length; ++i) {
   218→      address asset = removes[i];
   219→
   220→      _onFeedInfoUpdate(asset, true);
   221→
   222→      if (!s_allowlistedAssets.remove(asset)) {
   223→        revert Errors.AssetNotAllowlisted(asset);
   224→      }
   225→
   226→      delete s_dataStreamsFeedIdToAsset[s_feedInfo[asset].dataStreamsFeedId];
   227→      delete s_feedInfo[asset];
   228→      delete s_dataStreamsPrice[asset];
   229→
   230→      emit AssetRemovedFromAllowlist(asset);
   231→    }
   232→
   233→    for (uint256 i; i < adds.length; ++i) {
   234→      FeedInfo memory feedInfo = adds[i].feedInfo;
   235→      address asset = adds[i].asset;
   236→
   237→      _onFeedInfoUpdate(asset, false);
   238→
   239→      if (asset == address(0)) {
   240→        revert Errors.InvalidZeroAddress();
   241→      }
   242→
   243→      if (
   244→        feedInfo.stalenessThreshold == 0
   245→          || (feedInfo.dataStreamsFeedId == bytes32(0) && feedInfo.usdDataFeed == AggregatorV3Interface(address(0)))
   246→      ) {
   247→        revert Errors.InvalidZeroValue();
   248→      }
   249→
   250→      if (feedInfo.dataStreamsFeedId != bytes32(0)) {
   251→        bytes32 dataStreamsFeedId = feedInfo.dataStreamsFeedId;
   252→
   253→        if (feedInfo.dataStreamsFeedDecimals == 0) {
   254→          revert InvalidFeedDecimals(dataStreamsFeedId);
   255→        }
   256→
   257→        uint16 version = uint16(bytes2(dataStreamsFeedId));
   258→
   259→        if (version != STREAMS_REPORT_V3) {
   260→          revert InvalidFeedVersion(dataStreamsFeedId, version);
   261→        }
   262→
   263→        // Look up previous owner of this feed ID before overwriting; clean up that asset's data streams state
   264→        // if the feed ID is being rotated to a different asset.
   265→        address previousAssetForFeedId = s_dataStreamsFeedIdToAsset[feedInfo.dataStreamsFeedId];
   266→        if (previousAssetForFeedId != address(0) && previousAssetForFeedId != asset) {
   267→          FeedInfo storage previousAssetFeedInfo = s_feedInfo[previousAssetForFeedId];
   268→
   269→          // Since the rotation is causing the Data Streams feed to be removed for the previous asset, we need to ensure
   270→          // there is still a valid price source for that asset.
   271→          if (address(previousAssetFeedInfo.usdDataFeed) == address(0)) {
   272→            revert Errors.InvalidZeroValue();
   273→          }
   274→
   275→          previousAssetFeedInfo.dataStreamsFeedId = bytes32(0);
   276→          previousAssetFeedInfo.dataStreamsFeedDecimals = 0;
   277→          delete s_dataStreamsPrice[previousAssetForFeedId];
   278→        }
   279→
   280→        if (previousAssetForFeedId != asset) s_dataStreamsFeedIdToAsset[feedInfo.dataStreamsFeedId] = asset;
   281→      }
   282→
   283→      FeedInfo storage existingFeedInfo = s_feedInfo[asset];
   284→
   285→      if (s_allowlistedAssets.add(asset)) {
   286→        emit AssetAddedToAllowlist(asset);
   287→      } else if (existingFeedInfo.dataStreamsFeedId != feedInfo.dataStreamsFeedId) {
   288→        // If we are updating the feed ID for an already allowlisted asset, we need to clean up the old feed ID to asset
   289→        // mapping and the old price, as they will no longer be valid.
   290→        delete s_dataStreamsFeedIdToAsset[existingFeedInfo.dataStreamsFeedId];
   291→        delete s_dataStreamsPrice[asset];
   292→      }
   293→
   294→      s_feedInfo[asset] = FeedInfo({
   295→        dataStreamsFeedId: feedInfo.dataStreamsFeedId,
   296→        usdDataFeed: feedInfo.usdDataFeed,
   297→        dataStreamsFeedDecimals: feedInfo.dataStreamsFeedDecimals,
   298→        stalenessThreshold: feedInfo.stalenessThreshold
   299→      });
   300→
   301→      emit FeedInfoUpdated(asset, feedInfo);
   302→    }
   303→  }
   304→
   305→  /// @dev This empty hook is provided to allow inheriting contracts to implement custom logic that should be executed
   306→  /// when feed information is updated, e.g. adding state dependant checks, emitting additional events, updating
   307→  /// auxiliary state, etc.
   308→  /// @param asset The address of the asset whose feed information was updated.
   309→  /// @param isRemoved Whether the feed information was removed or added/updated - true if removed, false if added or
   310→  /// updated.
   311→  function _onFeedInfoUpdate(
   312→    address asset,
   313→    bool isRemoved
   314→  ) internal virtual {}
   315→
   316→  // ================================================================================================
   317→  // │                                           Getters                                            │
   318→  // ================================================================================================
   319→
   320→  /// @notice Getter function to retrieve the address of the Data Streams VerifierProxy contract.
   321→  /// @return streamsVerifierProxy The address of the Data Streams VerifierProxy contract.
   322→  function getStreamsVerifierProxy() external view returns (IVerifierProxy streamsVerifierProxy) {
   323→    return i_streamsVerifierProxy;
   324→  }
   325→
   326→  /// @notice Getter function to retrieve the list of allowlisted assets.
   327→  /// @return allowlistedAssets List of allowlisted assets.
   328→  function getAllowlistedAssets() external view returns (address[] memory allowlistedAssets) {
   329→    return s_allowlistedAssets.values();
   330→  }
   331→
   332→  /// @notice Getter function to retrieve feed information for a given feed ID.
   333→  /// @param asset The address of the asset.
   334→  /// @return feedInfo The feed information associated with the feed ID.
   335→  function getFeedInfo(
   336→    address asset
   337→  ) external view returns (FeedInfo memory feedInfo) {
   338→    return s_feedInfo[asset];
   339→  }
   340→
   341→  /// @notice Getter function to retrieve the asset address for a given Data Streams feed ID.
